-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft')
-- تحت "التربية الإيمانية" (tarbiya-imaniyya) — تستنفد العنقود بالكامل
-- (9 تصنيفات فرعية من أصل 9، كلها بلا محتوى): أعمال القلوب، التزكية
-- والمحاسبة، المجاهدة، الثبات والاستقامة، علاج الفتور، علو الهمة وطلب
-- العلم، بناء العادات، قيام الليل والتدبر، الصحبة الصالحة.
-- كل تصنيف يحصل على درس واحد حقيقي (lessons + lesson_sections +
-- lesson_citations)، مبني على مصادر معتمدة مسمّاة: مدارج السالكين
-- لابن القيم، إحياء علوم الدين للغزالي، رياض الصالحين للنووي، تزكية
-- النفس لابن رجب، الزهد والرقائق لابن المبارك.
-- كل آية استُشهد بها (البقرة:165، الشمس:9-10، العنكبوت:69، فصلت:30،
-- يوسف:87، طه:114، الرعد:11، المزمل:6، الزخرف:67) تحقَّقت حرفياً من
-- artifacts/majalis/public/data/quran محلياً عبر حقل numberInSurah
-- قبل الإدراج.
-- كل حديث مستشهَد به (9 أحاديث) متحقَّق حرفياً عبر WebSearch قبل
-- الإدراج: «إنما الأعمال بالنيات» (متفق عليه، عمر بن الخطاب)، «الكيس
-- من دان نفسه وعمل لما بعد الموت» (الترمذي، حسن، شداد بن أوس)،
-- «والمجاهد من جاهد نفسه في طاعة الله» (أحمد وابن حبان في صحيحه،
-- صححه الألباني، فضالة بن عبيد)، «قل آمنت بالله ثم استقم» (مسلم،
-- سفيان بن عبد الله الثقفي)، «إن لكل عمل شرة ولكل شرة فترة» (ابن حبان
-- في صحيحه وأحمد، حسَّنه الألباني، عبدالله بن عمرو)، «من سلك طريقاً
-- يلتمس فيه علماً سهل الله له به طريقاً إلى الجنة» (مسلم، أبو هريرة)،
-- «أحب الأعمال إلى الله أدومها وإن قل» (متفق عليه، عائشة)، «أفضل
-- الصلاة بعد الفريضة صلاة الليل» (مسلم، أبو هريرة)، «إنما مثل الجليس
-- الصالح والجليس السوء كحامل المسك ونافخ الكير» (متفق عليه، أبو موسى
-- الأشعري).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات التسعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) أعمال القلوب
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='6142e2e6-4a71-4a04-b912-950c66b416d8' AND title='أعمال القلوب وأصل صلاحها الإخلاص والمحبة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أعمال القلوب وأصل صلاحها الإخلاص والمحبة', 'معنى أعمال القلوب ومكانتها من الدين، وأصل صلاح الأعمال كلها بالنية الخالصة ومحبة الله تعالى', '6142e2e6-4a71-4a04-b912-950c66b416d8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها ومكانتها', 'أعمال القلوب: هي ما يقوم بالقلب من إيمان ومحبة وخوف ورجاء وتوكل وإخلاص، وهي أصل أعمال الجوارح وروحها، إذ لا يقبل عمل ظاهر إلا بصلاح باطنه. وأعظم هذه الأعمال محبة الله تعالى فوق كل محبة، وإخلاص النية له وحده في كل قول وعمل، فبصلاح القلب يصلح سائر الجسد.', 1),
    (v_lesson, 'evidence', 'أصل المحبة والإخلاص', 'قال تعالى: ﴿وَالَّذِينَ آمَنُوا أَشَدُّ حُبًّا لِّلَّهِ﴾ (البقرة: 165)، وعن عمر بن الخطاب رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «إِنَّمَا الْأَعْمَالُ بِالنِّيَّاتِ، وَإِنَّمَا لِكُلِّ امْرِئٍ مَا نَوَى» متفق عليه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'مدارج السالكين بين منازل إياك نعبد وإياك نستعين — ابن القيم الجوزية (باب أعمال القلوب)', 1);
  END IF;

  -- 2) التزكية والمحاسبة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='81142cfe-9c54-42d5-8f96-74624c4e7711' AND title='تزكية النفس ومحاسبتها طريق الفلاح') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تزكية النفس ومحاسبتها طريق الفلاح', 'معنى تزكية النفس ومحاسبتها، وأثرهما في فلاح العبد ونجاته، وخسران من أهمل نفسه واتبع هواها', '81142cfe-9c54-42d5-8f96-74624c4e7711', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفهما', 'تزكية النفس: تطهيرها من الرذائل وتحليتها بالفضائل حتى تسمو عن دنس الشهوات. والمحاسبة: أن يقف العبد مع نفسه وقفة تأمل يحاسبها على ما قدَّمت من خير أو شر قبل أن تُحاسَب يوم القيامة، فمن حاسب نفسه في الدنيا خفَّ حسابه في الآخرة، ومن أهملها اتبعت هواها فهلكت.', 1),
    (v_lesson, 'evidence', 'أصل الفلاح بالتزكية', 'قال تعالى: ﴿قَدْ أَفْلَحَ مَن زَكَّاهَا * وَقَدْ خَابَ مَن دَسَّاهَا﴾ (الشمس: 9-10)، وعن شداد بن أوس رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «الْكَيِّسُ مَنْ دَانَ نَفْسَهُ وَعَمِلَ لِمَا بَعْدَ الْمَوْتِ، وَالْعَاجِزُ مَنْ أَتْبَعَ نَفْسَهُ هَوَاهَا وَتَمَنَّى عَلَى اللَّهِ»، رواه الترمذي وقال: حديث حسن.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تزكية النفس — الحافظ زين الدين ابن رجب الحنبلي', 1);
  END IF;

  -- 3) المجاهدة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='0240be8c-bfbe-4ac5-9bd2-7e89ae147be7' AND title='مجاهدة النفس طريق الهداية والفلاح') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مجاهدة النفس طريق الهداية والفلاح', 'معنى مجاهدة النفس ومنازلها، ووعد الله بهداية من جاهد نفسه وهواه في طاعته', '0240be8c-bfbe-4ac5-9bd2-7e89ae147be7', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها', 'المجاهدة: بذل العبد جهده في قهر نفسه الأمَّارة بالسوء وحملها على طاعة الله وكفِّها عن هواها وشهواتها، وهي أصل كل جهاد، إذ لا يقوى العبد على جهاد عدوه الظاهر حتى يجاهد نفسه وهواه أولاً. وقد جعل الله الهداية إلى سبله جزاءً لمن صدق في هذه المجاهدة.', 1),
    (v_lesson, 'evidence', 'أصل وعد الهداية بالمجاهدة', 'قال تعالى: ﴿وَالَّذِينَ جَاهَدُوا فِينَا لَنَهْدِيَنَّهُمْ سُبُلَنَا وَإِنَّ اللَّهَ لَمَعَ الْمُحْسِنِينَ﴾ (العنكبوت: 69)، وعن فضالة بن عبيد رضي الله عنه أن رسول الله صلى الله عليه وسلم قال في حجة الوداع: «وَالْمُجَاهِدُ مَنْ جَاهَدَ نَفْسَهُ فِي طَاعَةِ اللَّهِ»، رواه أحمد وابن حبان في صحيحه وصححه الألباني.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'مدارج السالكين بين منازل إياك نعبد وإياك نستعين — ابن القيم الجوزية (منزلة المجاهدة)', 1);
  END IF;

  -- 4) الثبات والاستقامة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='434b7f34-7478-423e-a3cc-83189e4b0233' AND title='الاستقامة على الدين وثمرة الثبات عليها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الاستقامة على الدين وثمرة الثبات عليها', 'معنى الاستقامة الجامع الذي أوصى به النبي صلى الله عليه وسلم، وبشارة الثابتين عليها عند الموت', '434b7f34-7478-423e-a3cc-83189e4b0233', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها', 'الاستقامة: لزوم الصراط المستقيم بامتثال الأوامر واجتناب النواهي دون ميل يمنة أو يسرة، وهي جماع الدين كله، ولذلك وصفها النبي صلى الله عليه وسلم بأنها قول جامع لا يحتاج معه صاحبه إلى سؤال غيره. وقد وعد الله الثابتين عليها ببشارة الملائكة عند الموت وزوال الخوف والحزن.', 1),
    (v_lesson, 'evidence', 'أصل بشارة المستقيمين', 'قال تعالى: ﴿إِنَّ الَّذِينَ قَالُوا رَبُّنَا اللَّهُ ثُمَّ اسْتَقَامُوا تَتَنَزَّلُ عَلَيْهِمُ الْمَلَائِكَةُ أَلَّا تَخَافُوا وَلَا تَحْزَنُوا وَأَبْشِرُوا بِالْجَنَّةِ﴾ (فصلت: 30)، وعن سفيان بن عبد الله الثقفي رضي الله عنه قال: قلت: يا رسول الله، قل لي في الإسلام قولاً لا أسأل عنه أحداً بعدك، قال: «قُلْ آمَنْتُ بِاللَّهِ ثُمَّ اسْتَقِمْ»، رواه مسلم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'رياض الصالحين — الإمام يحيى بن شرف النووي (باب الاستقامة)', 1);
  END IF;

  -- 5) علاج الفتور
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='b923c5c5-236a-470d-8dbf-2ad1d7938b7d' AND title='الفتور سنة نفسية وطريق علاجه بالسنة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الفتور سنة نفسية وطريق علاجه بالسنة', 'بيان أن للفتور بعد النشاط سنة جارية في النفوس، والفرق بين فتور يهدي إلى الاعتدال وفتور يهلك صاحبه', 'b923c5c5-236a-470d-8dbf-2ad1d7938b7d', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وأقسامه', 'الفتور: ضعف الهمة وسكون النشاط بعد قوته، وهو أمر جارٍ على النفوس لا يخلو منه سالك. لكن الفتور المحمود ما كانت غايته الرجوع إلى هدي النبي صلى الله عليه وسلم واعتداله، والفتور المذموم ما انتهى بصاحبه إلى ترك الطاعة بالكلية أو الابتداع فيها. وعلاج ذلك عدم اليأس من رحمة الله والاستمرار على القصد وإن قلَّ.', 1),
    (v_lesson, 'evidence', 'أصل النهي عن اليأس وضابط الفتور', 'قال تعالى: ﴿وَلَا تَيْأَسُوا مِن رَّوْحِ اللَّهِ إِنَّهُ لَا يَيْأَسُ مِن رَّوْحِ اللَّهِ إِلَّا الْقَوْمُ الْكَافِرُونَ﴾ (يوسف: 87)، وعن عبد الله بن عمرو رضي الله عنهما أن رسول الله صلى الله عليه وسلم قال: «إِنَّ لِكُلِّ عَمَلٍ شِرَّةً، وَلِكُلِّ شِرَّةٍ فَتْرَةً، فَمَنْ كَانَتْ فَتْرَتُهُ إِلَى سُنَّتِي فَقَدِ اهْتَدَى، وَمَنْ كَانَتْ إِلَى غَيْرِ ذَلِكَ فَقَدْ هَلَكَ»، رواه ابن حبان في صحيحه وأحمد، وحسَّنه الألباني.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الزهد والرقائق — الإمام عبد الله بن المبارك', 1);
  END IF;

  -- 6) علو الهمة وطلب العلم
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='e08436ff-92cb-446f-a8ca-35c5e0901761' AND title='علو الهمة في طلب العلم وفضل سالكه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('علو الهمة في طلب العلم وفضل سالكه', 'حث القرآن على الازدياد من العلم، وبيان النبي صلى الله عليه وسلم أن طالب العلم على طريق موصل إلى الجنة', 'e08436ff-92cb-446f-a8ca-35c5e0901761', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'معناها', 'علو الهمة في طلب العلم: أن يجتهد العبد في تحصيل العلم النافع ولا يقنع بأدنى القدر منه ولا يفتر عن الازدياد، فإن العلم الشرعي أصل صلاح الدين والدنيا، وطلبه عبادة يُبتغى بها وجه الله، ولذلك خصه الشرع بفضائل عظيمة لسالكه تكريماً لمقامه.', 1),
    (v_lesson, 'evidence', 'أصل طلب الازدياد وفضل السالك', 'قال تعالى: ﴿وَقُل رَّبِّ زِدْنِي عِلْمًا﴾ (طه: 114)، وعن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «مَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللَّهُ لَهُ بِهِ طَرِيقًا إِلَى الْجَنَّةِ»، رواه مسلم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'إحياء علوم الدين — الإمام أبو حامد الغزالي (كتاب العلم)', 1);
  END IF;

  -- 7) بناء العادات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='0b8bb5e9-efd7-4957-a810-b9be6c944d1b' AND title='بناء العادات الصالحة بالمداومة والتدرج') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('بناء العادات الصالحة بالمداومة والتدرج', 'أثر تغيير الإنسان لنفسه في تغيير حاله، وحب النبي صلى الله عليه وسلم للعمل القليل الدائم على الكثير المنقطع', '0b8bb5e9-efd7-4957-a810-b9be6c944d1b', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أساسها', 'بناء العادات الصالحة: ترسيخ سلوك حسن في النفس بتكراره حتى يصير طبعاً ثابتاً لا يحتاج معه العبد إلى مجاهدة شاقة في كل مرة، وأساس ذلك المداومة على القليل من العمل واستمراره دون انقطاع، لا الإكثار منه ثم تركه، فالعمل الدائم وإن قلَّ أثبت في النفس وأحب إلى الله من المنقطع الكثير.', 1),
    (v_lesson, 'evidence', 'أصل التغيير والمداومة', 'قال تعالى: ﴿إِنَّ اللَّهَ لَا يُغَيِّرُ مَا بِقَوْمٍ حَتَّىٰ يُغَيِّرُوا مَا بِأَنفُسِهِمْ﴾ (الرعد: 11)، وعن عائشة رضي الله عنها أن النبي صلى الله عليه وسلم سُئل: أي الأعمال أحب إلى الله؟ قال: «أَدْوَمُهَا وَإِنْ قَلَّ» متفق عليه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'رياض الصالحين — الإمام يحيى بن شرف النووي (باب المحافظة على الأعمال الصالحة)', 1);
  END IF;

  -- 8) قيام الليل والتدبر
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='7a4e0eb8-203a-4c19-acf9-e61fd2a9d382' AND title='قيام الليل وتدبر القرآن أفضل نافلة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('قيام الليل وتدبر القرآن أفضل نافلة', 'فضل قيام الليل وكونه أفضل الصلاة بعد الفريضة، وأثر خلوة الليل في قوة القول وصدق التدبر', '7a4e0eb8-203a-4c19-acf9-e61fd2a9d382', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وأثره', 'قيام الليل: التعبد بالصلاة والدعاء وتلاوة القرآن في جوف الليل بعد النوم أو قبله، وهو من أعظم أسباب صلاح القلب لخلوّ الليل من الشواغل واجتماع القلب واللسان فيه على المعنى. ويرتبط قيام الليل بتدبر القرآن ارتباطاً وثيقاً، إذ في هدوء الليل يتهيأ القلب للتأمل في آياته وفهم معانيها.', 1),
    (v_lesson, 'evidence', 'أصل فضل ناشئة الليل', 'قال تعالى: ﴿إِنَّ نَاشِئَةَ اللَّيْلِ هِيَ أَشَدُّ وَطْئًا وَأَقْوَمُ قِيلًا﴾ (المزمل: 6)، وعن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «أَفْضَلُ الصَّلَاةِ بَعْدَ الْفَرِيضَةِ صَلَاةُ اللَّيْلِ»، رواه مسلم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'رياض الصالحين — الإمام يحيى بن شرف النووي (باب فضل قيام الليل)', 1);
  END IF;

  -- 9) الصحبة الصالحة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='422cc9ae-b3d2-4a08-a288-88de6977987b' AND title='أثر الصحبة الصالحة وخطر صحبة أهل السوء') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أثر الصحبة الصالحة وخطر صحبة أهل السوء', 'بيان أن الخلة يوم القيامة تنقلب عداوة إلا بين المتقين، وضرب النبي صلى الله عليه وسلم المثل بحامل المسك ونافخ الكير للجليس الصالح والسوء', '422cc9ae-b3d2-4a08-a288-88de6977987b', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أثرها', 'الصحبة الصالحة: مخالطة أهل الخير والتقوى ومجالستهم، وأثرها يتعدى صاحبها إلى جليسه بالنفع كما ينتفع من حامل المسك ولو لم يشتر منه. وصحبة السوء بضدها، فهي خسارة وضرر يتعدى إلى الجليس ولو لم يقصد الأذى، ولذلك وجَّه الشرع إلى انتقاء الصاحب لأنه دليل على دين المرء وخلقه.', 1),
    (v_lesson, 'evidence', 'أصل انقلاب الخلة عداوة ومثل الجليسين', 'قال تعالى: ﴿الْأَخِلَّاءُ يَوْمَئِذٍ بَعْضُهُمْ لِبَعْضٍ عَدُوٌّ إِلَّا الْمُتَّقِينَ﴾ (الزخرف: 67)، وعن أبي موسى الأشعري رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «إِنَّمَا مَثَلُ الْجَلِيسِ الصَّالِحِ وَالْجَلِيسِ السَّوْءِ كَحَامِلِ الْمِسْكِ وَنَافِخِ الْكِيرِ، فَحَامِلُ الْمِسْكِ إِمَّا أَنْ يُحْذِيَكَ، وَإِمَّا أَنْ تَبْتَاعَ مِنْهُ، وَإِمَّا أَنْ تَجِدَ مِنْهُ رِيحًا طَيِّبَةً، وَنَافِخُ الْكِيرِ إِمَّا أَنْ يُحْرِقَ ثِيَابَكَ، وَإِمَّا أَنْ تَجِدَ رِيحًا خَبِيثَةً» متفق عليه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'إحياء علوم الدين — الإمام أبو حامد الغزالي (كتاب آداب الصحبة والمعاشرة)', 1);
  END IF;

